import{_ as t,c as a,o as n,ae as i}from"./chunks/framework.CMFi8ROq.js";const l="/mrdu/assets/ChatGpt.Ci072p8o.png",r="/mrdu/assets/LLM-Agent.BR_iLmrN.svg",_=JSON.parse('{"title":"Agent","description":"","frontmatter":{},"headers":[],"relativePath":"ai-guide/Agent.md","filePath":"ai-guide/Agent.md","lastUpdated":1777978720000}'),o={name:"ai-guide/Agent.md"};function s(g,e,d,h,A,c){return n(),a("div",null,e[0]||(e[0]=[i('<h1 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;Agent&quot;">​</a></h1><h2 id="什么是-agent" tabindex="-1">什么是 Agent <a class="header-anchor" href="#什么是-agent" aria-label="Permalink to &quot;什么是 Agent&quot;">​</a></h2><p>Agent（Ai 智能体）是一个“以大模型为核心决策引擎，进行自主决策并采取行动”的系统。做一个简单的比喻：大模型就相当于一个“大脑”，Agent 就相当于“装上大脑的执行系统”，它能够根据大模型的决策，进行自主决策并采取行动。</p><p>从技术层面看，Agent 通常由以下四个部分而成：</p><ul><li>大脑 (LLM)：负责逻辑推理、意图识别和语言表达。</li><li>规划 (Planning)：Agent 会把大任务拆解成“第一步、第二步、第三步”。如果中间出错了，他还会自我反思并修正计划。</li><li>记忆 (Memory)： <ul><li>短时记忆：当前的对话上下文。</li><li>长时记忆：通常通过 RAG（检索增强生成）技术，存储你的个人知识库或历史行为。</li></ul></li><li>工具使用：这是 Agent 的“手脚”。通过 Skills（技能包）和 MCP（万能接口），他可以去查实时天气、操作 Excel、甚至在你的服务器上部署代码。</li></ul><p>一个很直观的例子是 ChatGPT，就是一个 Agent，我们每次和 ChatGPT 对话，它就会根据我们输入的上下文，进行逻辑推理、意图识别和语言表达，然后根据我们的意图，进行自主决策并采取行动。 <img src="'+l+'" alt="Agent"></p><p><img src="'+r+'" alt="LLM-Agent"></p><h2 id="为什么需要-agent" tabindex="-1">为什么需要 Agent <a class="header-anchor" href="#为什么需要-agent" aria-label="Permalink to &quot;为什么需要 Agent&quot;">​</a></h2><h2 id="agent-的分类" tabindex="-1">Agent 的分类 <a class="header-anchor" href="#agent-的分类" aria-label="Permalink to &quot;Agent 的分类&quot;">​</a></h2><h2 id="多智能体系统" tabindex="-1">多智能体系统 <a class="header-anchor" href="#多智能体系统" aria-label="Permalink to &quot;多智能体系统&quot;">​</a></h2><p>多智能体系统（MAS, Multi-Agent System）</p>',11)]))}const u=t(o,[["render",s]]);export{_ as __pageData,u as default};
